//! `mask_stack!` rejects a literal whose inline `[u8; N]` buffer would
//! exceed the `LITMASK_STACK_LIMIT` byte cap (default 4096) — large
//! secrets belong on the heap via `mask!`. The literal below is 5000
//! bytes, over the default cap.

use litmask::mask_stack;

fn main() {
    let _ = mask_stack!("");
}
